import React from 'react';
import styles from './cart-wrapper.module.css';
import CartLayout from '../../layout/cart-layout';

const CartWrapper = () => {
  return (
    <div className={styles.wrapper_cart}>
        <div className='container'>
            <CartLayout>
                <div className={styles.wrapper_table_header}>

                </div>
                <h6>Product</h6>
                <h6>Price</h6>
                <h6>Quantity</h6>
                <h6>Total</h6>
            </CartLayout>

        </div>

    </div>
  )
}

export default CartWrapper
